# Build lookup: permalink -> correct username
perm_to_user = {}
for row in batch3_data:
    permalink, owner_id = row
    username = OWNER_MAP.get(owner_id, owner_id)  # keep raw id if unknown
    perm_to_user[permalink] = username

print(f"Batch3 lookup: {len(perm_to_user)} permalinks")

# Load postsRaw
with open("_postsRaw.json", encoding="utf-8") as f:
    posts = json.load(f)

print(f"Total posts: {len(posts)}")

# Format: [date, username, tipo, caption, permalink, reach, likes, comments, shares, saves, total_interactions]
# Index 1 = username, Index 4 = permalink

fixed = 0
unchanged = 0
not_found = 0
missing_perms = set()

# Load the missing perms list to know which ones to fix
import os
missing_path = os.path.join(os.path.dirname(__file__), '..', 'G4-Workspace', '_missing_perms.json')
if os.path.exists(missing_path):
    with open(missing_path, encoding="utf-8") as f:
        target_perms = set(json.load(f))
else:
    target_perms = set(perm_to_user.keys())

print(f"Target permalinks to fix: {len(target_perms)}")

for post in posts:
    permalink = post[4]
    if permalink in perm_to_user:
        correct_user = perm_to_user[permalink]
        if post[1] != correct_user:
            post[1] = correct_user
            fixed += 1
        else:
            unchanged += 1
    elif permalink in target_perms:
        not_found += 1
        missing_perms.add(permalink)

print(f"Fixed: {fixed}, Already correct: {unchanged}, Not in Genie data: {not_found}")

# Count by username after fix
from collections import Counter
user_counts = Counter(p[1] for p in posts)
print(f"Distribution after fix: {dict(sorted(user_counts.items()))}")

# Save
with open("_postsRaw.json", "w", encoding="utf-8") as f:
    json.dump(posts, f, separators=(",", ":"), ensure_ascii=False)

print(f"Saved _postsRaw.json ({len(posts)} posts)")

if missing_perms:
    print(f"WARNING: {len(missing_perms)} permalinks still missing owner data")
